// ---- Pillar 2: Social Posts — Article → LinkedIn post + Twitter thread via Groq ----
// Input: { keyword: '...', title: '...', article: '...' }
//   OR:  { content_pipeline_id: 'uuid' }  — fetches article from Supabase
// LLM: Groq 8b for social (fast, no need for 70b) → Cerebras fallback
// Cost: one LLM call total (both formats in one prompt)
const ENV = (typeof $env !== 'undefined' && $env) ? $env : process.env;
const b = $json.body || $json;

let keyword = b.keyword || '';
let title   = b.title   || '';
let article = b.article || '';

// Fetch from Supabase if ID provided
if (b.content_pipeline_id && ENV.SUPABASE_URL) {
  const row = await this.helpers.httpRequest({
    method: 'GET',
    url: `${ENV.SUPABASE_URL}/rest/v1/content_pipeline?id=eq.${b.content_pipeline_id}&select=keyword,topic,article_draft`,
    headers: { apikey: ENV.SUPABASE_ANON_KEY, Authorization: `Bearer ${ENV.SUPABASE_ANON_KEY}` },
    json: true, timeout: 10000
  }).catch(() => []);
  if (row.length) { keyword = row[0].keyword; title = row[0].topic; article = row[0].article_draft; }
}

if (!title && !article) return [{ json: { ok: false, error: 'Provide title+article or content_pipeline_id' } }];

// Strip HTML tags for LLM input (saves tokens)
const cleanArticle = article.replace(/<[^>]+>/g, ' ').replace(/\s+/g, ' ').slice(0, 3000);

const SYSTEM = `You are a B2B content marketer for Markexis — specialists in LatAm Market Entry, AI Marketing, and GTM Strategy.
Write high-performing social content:
- LinkedIn: 150-250 words, hook first line (no question openers), 3-5 punchy insights, call to action, 3-5 relevant hashtags
- Twitter thread: 5-7 tweets, each ≤ 280 chars, numbered (1/ 2/ etc.), hook tweet first, last tweet is CTA to read full article
Tone: expert, direct, specific — never generic. Cite specifics from the article.`;

const USER = `Article: "${title}"\nKeyword: ${keyword}\n\nArticle excerpt:\n${cleanArticle}\n\nReturn JSON: { "linkedin_post": "...", "twitter_thread": ["tweet1", "tweet2", ...] }`;

let parsed = {};
const providers = [
  { url: 'https://api.groq.com/openai/v1/chat/completions', key: ENV.GROQ_API_KEY, model: 'llama-3.1-8b-instant' },
  { url: 'https://api.cerebras.ai/v1/chat/completions', key: ENV.CEREBRAS_API_KEY, model: 'llama3.1-70b' },
];
for (const p of providers) {
  if (!p.key) continue;
  try {
    const res = await this.helpers.httpRequest({
      method: 'POST', url: p.url,
      headers: { Authorization: `Bearer ${p.key}`, 'Content-Type': 'application/json' },
      body: JSON.stringify({ model: p.model, messages: [{role:'system',content:SYSTEM},{role:'user',content:USER}], temperature: 0.6, max_tokens: 1024, response_format: { type: 'json_object' } }),
      json: true, timeout: 30000
    });
    parsed = JSON.parse(res.choices[0].message.content);
    break;
  } catch { continue; }
}

if (!parsed.linkedin_post) return [{ json: { ok: false, error: 'LLM returned no content', keyword } }];

// Store back to content_pipeline
if (ENV.SUPABASE_URL && keyword) {
  await this.helpers.httpRequest({
    method: 'POST',
    url: `${ENV.SUPABASE_URL}/rest/v1/content_pipeline?on_conflict=keyword`,
    headers: {
      apikey: ENV.SUPABASE_ANON_KEY, Authorization: `Bearer ${ENV.SUPABASE_ANON_KEY}`,
      'Content-Type': 'application/json', Prefer: 'resolution=merge-duplicates'
    },
    body: JSON.stringify({
      keyword,
      linkedin_post: parsed.linkedin_post,
      twitter_thread: JSON.stringify(parsed.twitter_thread),
      updated_at: new Date().toISOString()
    }),
    json: false, timeout: 15000
  }).catch(() => null);
}

return [{ json: { ok: true, keyword, linkedin_post: parsed.linkedin_post, twitter_thread: parsed.twitter_thread, tweet_count: parsed.twitter_thread?.length || 0 } }];
